const data = this.getValues();
const exchangeRate = data.exchange_rate;
let items = [];

if (data.table_si.length > 0) {
  items = data.table_si;
} else {
  const { SILineItem } = arguments[0];
  items = SILineItem;
}

let totalGross = 0;
let totalDiscount = 0;
let totalTax = 0;
let totalAmount = 0;

const roundPrice = (value) => {
  return parseFloat(parseFloat(value || 0).toFixed(4));
};

if (Array.isArray(items)) {
  items.forEach((item, index) => {
    // Ensure values are numeric
    const quantity = Number(item.invoice_qty) || 0;
    const unitPrice = roundPrice(item.unit_price) || 0;
    const grossValue = quantity * unitPrice;

    totalGross += roundPrice(grossValue);

    // Set gross value
    this.setData({
      [`table_si.${index}.gross`]: roundPrice(grossValue),
      [`table_si.${index}.si_amount`]: roundPrice(grossValue),
      invoice_subtotal: roundPrice(totalGross),
    });

    // Get discount, discountUOM, and tax info for this row
    let discount = parseFloat(item.si_discount) || 0;
    let discountUOM = item.si_discount_uom_id;
    const taxRate = Number(item.tax_percent) || 0;
    const taxInclusive = item.si_tax_inclusive;
    let discountAmount = 0.0;

    if (discount > 0) {
      if (!discountUOM) {
        discountUOM = "Amount";
        this.setData({ [`table_si.${index}.si_discount_uom_id`]: discountUOM });
      }
    }

    if (discountUOM) {
      // Calculate discount amount using UOM from database
      if (discount !== 0) {
        if (discountUOM === "Amount") {
          discountAmount = roundPrice(discount);
        } else if (discountUOM === "%") {
          discountAmount = roundPrice((grossValue * discount) / 100);
        }

        if (discountAmount > grossValue) {
          discount = 0;
          discountAmount = 0;

          this.setData({
            [`table_si.${index}.si_discount`]: 0,
            [`table_si.${index}.discount_amount`]: 0,
          });
        } else {
          this.setData({
            [`table_si.${index}.discount_amount`]: roundPrice(discountAmount),
          });
        }
      }
    } else {
      this.setData({
        [`table_si.${index}.discount_amount`]: 0,
      });
    }
    // Calculate amount after discount
    const amountAfterDiscount = roundPrice(grossValue - discountAmount);

    // Calculate tax amount based on taxInclusive flag
    let taxAmount = 0;
    let finalAmount = amountAfterDiscount;

    if (taxRate) {
      const taxRateDecimal = taxRate / 100;

      if (taxInclusive === 1) {
        taxAmount = roundPrice(
          amountAfterDiscount - amountAfterDiscount / (1 + taxRateDecimal)
        );
        finalAmount = amountAfterDiscount;
      } else {
        taxAmount = roundPrice(amountAfterDiscount * taxRateDecimal);
        finalAmount = amountAfterDiscount + taxAmount;
      }

      // Set tax amount
      this.setData({
        [`table_si.${index}.tax_amount`]: taxAmount,
      });
    } else {
      this.setData({
        [`table_si.${index}.tax_amount`]: 0,
      });
    }

    // Set final amount
    this.setData({
      [`table_si.${index}.si_amount`]: roundPrice(finalAmount),
    });

    // Subtract previous values before adding new ones
    totalDiscount += roundPrice(discountAmount);
    totalTax += roundPrice(taxAmount);
    totalAmount += roundPrice(finalAmount);

    if (totalTax > 0) {
      this.display(["invoice_taxes_amount", "total_tax_currency"]);
    }

    // Set the total fields
    this.setData({
      invoice_total_discount: roundPrice(totalDiscount),
      invoice_taxes_amount: roundPrice(totalTax),
      invoice_total: roundPrice(totalAmount),
    });

    if (!exchangeRate) {
      return;
    } else {
      const myrTotal = exchangeRate * totalAmount;
      this.setData({
        myr_total_amount: roundPrice(myrTotal),
      });
    }
  }); // This closing bracket was missing for the forEach callback
} else {
  console.log("Not an array:", items);
}

